#include<bits/stdc++.h>
using namespace std;
long long n;
long long ans=0,sum=0;
vector<pair<long long,long long>> mp[20010];
long long f[20010][3];
void dfs(long long x,long long fa)
{
    f[x][0]=1;
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=fa)
        {
            dfs(v,x);
            for(long long i=0;i<3;i++)
            {
                ans+=f[v][i]*f[x][((-i-val)%3+3)%3]*2;
            }
            for(long long i=0;i<3;i++)
            {
                f[x][(i+val)%3]+=f[v][i];
            }
        }
    }
}
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        w%=3;
        mp[u].push_back({v,w});
        mp[v].push_back({u,w});
    }
    dfs(1,-1);
    ans+=n;
    sum=n*n;
    long long g=gcd(ans,sum);
    printf("%lld/%lld",ans/g,sum/g);
    return 0;
}
